import React, { useState } from 'react';

const Settings = () => {
  const [apiKey, setApiKey] = useState('');
  const [avoidTolls, setAvoidTolls] = useState(false);
  const [avoidHighways, setAvoidHighways] = useState(false);

  const saveSettings = () => {
    localStorage.setItem('googleMapsApiKey', apiKey);
    localStorage.setItem('avoidTolls', avoidTolls);
    localStorage.setItem('avoidHighways', avoidHighways);
    alert('Settings saved');
  };

  return (
    <div className="settings">
      <h2>Settings</h2>
      <input type="text" placeholder="Google Maps API Key" value={apiKey} onChange={(e) => setApiKey(e.target.value)} />
      <label>
        <input type="checkbox" checked={avoidTolls} onChange={(e) => setAvoidTolls(e.target.checked)} />
        Avoid Tolls
      </label>
      <label>
        <input type="checkbox" checked={avoidHighways} onChange={(e) => setAvoidHighways(e.target.checked)} />
        Avoid Highways
      </label>
      <button onClick={saveSettings}>Save</button>
    </div>
  );
};

export default Settings;
